/* Auto-generated — Kit Logo Pack, 40 files (1 README + 39 SVGs), stored as base64 ZIP */
window.__KIT_LOGO_PACK_ZIP_B64 = "";
window.downloadKitLogoPack = function() {
  const b64 = window.__KIT_LOGO_PACK_ZIP_B64;
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  const blob = new Blob([bytes], { type: 'application/zip' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'kit-logo-pack.zip';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 1000);
};
